SELECT COUNT(*) 
FROM INQUIRY


        AND category = #{category}


        AND status = #{status}


        AND (title LIKE '%'||#{keyword}||'%' OR user_id LIKE '%'||#{keyword}||'%')


SELECT * FROM (
    SELECT a.*, rownum rnum FROM (
        SELECT * FROM INQUIRY 



                AND category = #{category}


                AND status = #{status}


                AND (title LIKE '%' || #{keyword} || '%' OR user_id LIKE '%' || #{keyword} || '%')



        ORDER BY inquiry_id DESC
    ) a 
    WHERE rownum <= #{endRow}
) 
WHERE rnum >= #{startRow}
